    """Add a new comment to the specified post."""

    global comment_counter

    try:
        # Extract comment body from the incoming data
        body = data.get('body')

        # Validate input data
        if not body:
            return {
                'message': 'Comment body is required.'
            }, 400

        # Check if the post exists
